                        io_print("  VALUE ERROR");
                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
                        putchar(10);
                    } else if (eval_err == 3) {
                        heap_top = heap_save;
                        io_print("  LENGTH ERROR");
                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
                        putchar(10);
                    } else if (eval_err == 4) {
                        heap_top = heap_save;
                        io_print("  RANK ERROR");
                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
                        putchar(10);
                    } else if (eval_err == 5) {
                        heap_top = heap_save;
                        io_print("  WS FULL");
                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
                        putchar(10);
                    } else if (eval_err) {
                        heap_top = heap_save;
                        io_print("  DOMAIN ERROR");
                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
