            branch_target = -1;
            continue;
        } else if (branch_target == 0) {
            // goto 0: stop execution
            if (pc >= 0) {
                // In program mode: return to immediate mode
                pc = -1;
                branch_target = -1;
                continue;
            }
            // In immediate mode: exit interpreter
            return 0;
        }

        // Advance PC if replaying stored lines
        if (pc >= 0) {
            pc++;
            if (pc >= prog_count) pc = -1;
        }
    }
    return 0;
}

