            int rk = arr_rank(v);
            if (rk == 0) {
                int r = arr_scalar(~arr_get(v, 0));
                if (r < 0) { eval_err = 5; return -1; }
                return r;
            }
            if (rk == 1) {
                int sz = arr_size(v);
                int r = arr_vector(sz);
                if (r < 0) { eval_err = 5; return -1; }
                int i = 0;
                while (i < sz) {
                    arr_set(r, i, ~arr_get(v, i));
                    i++;
                }
                return r;
            }
            if (rk == 2) {
                int d0 = arr_dim0(v);
                int d1 = arr_dim1(v);
                int r = arr_new(2, d0, d1);
                if (r < 0) { eval_err = 5; return -1; }
                int sz = d0 * d1;
                int i = 0;
                while (i < sz) {
                    arr_set(r, i, ~arr_get(v, i));
                    i++;
                }
                return r;
            }
            eval_err = 4;
            return -1;
        }

        if (res_id == RES_ROLL) {
            // roll N: random integer 1..N (element-wise on vectors)
            int rk = arr_rank(v);
            if (rk == 0) {
                int n_val = arr_get(v, 0);
                if (n_val <= 0) { eval_err = 1; return -1; }
                int r = arr_scalar(lcg_roll(n_val));
                if (r < 0) { eval_err = 5; return -1; }
                return r;
            }
            if (rk == 1) {
                int sz = arr_size(v);
                int r = arr_vector(sz);
                if (r < 0) { eval_err = 5; return -1; }
                int i = 0;
                while (i < sz) {
                    int n_val = arr_get(v, i);
                    if (n_val <= 0) { eval_err = 1; return -1; }
                    arr_set(r, i, lcg_roll(n_val));
                    i++;
                }
                return r;
            }
            eval_err = 4;
            return -1;
        }

        if (res_id == RES_FMT) {
