                int sz = arr_size(rv);
                int abs_n = count;
                if (abs_n < 0) abs_n = 0 - abs_n;
                if (abs_n > sz) { eval_err = 3; return -1; }

                int r = arr_vector(abs_n);
                if (r < 0) { eval_err = 5; return -1; }
                int start = 0;
                if (count < 0) start = sz - abs_n;
                int i = 0;
                while (i < abs_n) {
                    arr_set(r, i, arr_get(rv, start + i));
                    i++;
                }
                return r;
            }

